const getParsedSessionCookie = async (
  ctx: Context<Env>,
  options?: ParseSessionCookieOptions,
): Promise<z.infer<typeof sessionCookieSchema>> => {
  const { deleteOnError = false, deleteAfterAttempt = false } = options ?? {};
  try {
    // Retrieve session cookie data
    const sessionData = await getAuthCookie(ctx, 'session');

    // If no session data, return null
    if (!sessionData) throw new Error();

    // Parse delimited string: "<hashedSessionToken>.<sessionId>.<adminUserId>"
    const [sessionToken, sessionId, adminUserIdRaw] = sessionData.split('.');
    if (!sessionToken || !sessionId) throw new Error();

    const adminUserId = adminUserIdRaw || undefined;

    return sessionCookieSchema.parse({ sessionToken, sessionId, adminUserId });
  } catch (error) {
    if (deleteOnError) deleteAuthCookie(ctx, 'session');
    throw new AppError(401, 'unauthorized', 'warn');
  } finally {
    if (deleteAfterAttempt) deleteAuthCookie(ctx, 'session');
  }
};

app.openapi(authGeneralRoutes.stopImpersonation, async (ctx) => {
  const { sessionToken, adminUserId } = await getParsedSessionCookie(ctx, { deleteAfterAttempt: true });
  const { session } = await validateSession(sessionToken);

  // Only continue if session is impersonation
  if (!adminUserId) throw new AppError(400, 'invalid_request', 'error');

  const adminsLastSession = await findLatestSessionByUser(ctx, { userId: adminUserId });

  if (isExpiredDate(adminsLastSession.expiresAt)) throw new AppError(401, 'unauthorized', 'warn');

  const expireTimeSpan = new TimeSpan(new Date(adminsLastSession.expiresAt).getTime() - Date.now(), 'ms');
  const cookieContent = `${adminsLastSession.secret}.${adminsLastSession.userId ?? ''}`;

  await setAuthCookie(ctx, 'session', cookieContent, expireTimeSpan);

  logEvent(ctx, 'info', 'Stopped impersonation', { adminId: adminUserId, targetUserId: session.userId });

  return ctx.body(null, 204);
});

app.openapi(authPasskeysRoutes.deletePasskey, async (ctx) => {
  const user = ctx.var.user;

  const { id } = ctx.req.valid('param');

  // Remove passkey and conditionally disable MFA atomically
  await baseDb.transaction(async (tx) => {
    await tx.delete(passkeysTable).where(and(eq(passkeysTable.userId, user.id), eq(passkeysTable.id, id)));

    // Check if the user still has any passkeys or TOTP entries registered
    const { passkeys, totps } = await findRemainingMfaMethods({ var: { ...ctx.var, db: tx } }, { userId: user.id });

    // MFA requires both passkeys and TOTP as backup — disable if either is missing
    if (!passkeys.length || !totps.length) {
      await disableMfa({ var: { ...ctx.var, db: tx } }, { userId: user.id });
    }
  });

  sendAccountSecurityEmail(ctx, user, 'passkey-removed');

  return ctx.body(null, 204);
});

app.openapi(authTotpsRoutes.generateTotpKey, async (ctx) => {
  const user = ctx.var.user;

  // Prevent generating a new key if user already has TOTP configured
  const existingTotp = await findExistingTotp({ var: { ...ctx.var, db: baseDb } }, { userId: user.id });
  if (existingTotp) throw new AppError(409, 'resource_already_exists', 'warn');

  // Generate a 20-byte random secret and encode it as Base32
  const secretBytes = crypto.getRandomValues(new Uint8Array(20));

  // Base32 → for authenticator app (manual entry or QR code)
  const manualKey = encodeBase32UpperCase(secretBytes);

  // Save the secret in a short-lived cookie (5 minutes)
  await setAuthCookie(ctx, 'totp-challenge', manualKey, new TimeSpan(5, 'm'));

  // otpauth:// URI for QR scanner apps
  const totpUri = createTOTPKeyURI(
    appConfig.slug,
    user.email,
    secretBytes,
    appConfig.totpConfig.intervalInSeconds,
    appConfig.totpConfig.digits,
  );

  return ctx.json({ totpUri, manualKey }, 200);
});

