const validateConfirmMfaToken = async (ctx: Context<Env>): Promise<UserModel> => {
  const tokenFromCookie = await getAuthCookie(ctx, 'confirm-mfa');
  if (!tokenFromCookie)
    throw new AppError(401, 'confirm-mfa_not_found', 'error', {
      willRedirect: appConfig.mode !== 'test',
      meta: { errorPagePath: '/auth/error' },
    });

  // Fetch token record and associated user
  const tokenRecord = await getValidToken({
    ctx,
    token: tokenFromCookie,
    invokeToken: false,
    tokenType: 'confirm-mfa',
  });

  // Sanity check
  if (!tokenRecord.userId) throw new AppError(400, 'invalid_request', 'error');

  const [user] = await db.select(userSelect).from(usersTable).where(eq(usersTable.id, tokenRecord.userId)).limit(1);
  if (!user) throw new AppError(404, 'not_found', 'error', { entityType: 'user' });

  return user;
};

const handleOAuthVerification = async (ctx: Context<Env>, token: TokenModel) => {
  // Token requires userId and oauthAccountId
  if (!token.userId || !token.oauthAccountId) throw new AppError(500, 'server_error', 'error');

  const [oauthAccount] = await db
    .select()
    .from(oauthAccountsTable)
    .where(eq(oauthAccountsTable.id, token.oauthAccountId))
    .limit(1);
  if (!oauthAccount) throw new AppError(400, 'invalid_request', 'warn');

  const verifyPath = `/auth/${oauthAccount.provider}`;
  const verificationURL = new URL(verifyPath, appConfig.backendUrl);

  verificationURL.searchParams.set('tokenId', token.id);
  verificationURL.searchParams.set('type', 'verify');

  const reqRedirect = ctx.req.query('redirectAfter');
  if (reqRedirect) verificationURL.searchParams.set('redirectAfter', reqRedirect);

  return ctx.redirect(verificationURL, 302);
};

try {
  // Compare case-insensitively, since media types are case-insensitive and request validation
  // matches them the same way. Otherwise a body like `Application/JSON` could pass validation yet
  // never reach the handler as `req.body`.
  const contentType = (c.req.header('content-type') ?? '').toLowerCase()
  // An empty/absent Content-Type is treated as JSON to match request validation, so a headerless
  // JSON body that passes validation is still delivered to the handler as `req.body`.
  if (contentType === '' || contentType.includes('application/json')) {
    body = await c.req.json().catch(() => undefined)
  } else if (contentType.includes('application/x-www-form-urlencoded')) {
    body = await c.req.parseBody().catch(() => undefined)
  } else if (contentType.includes('text/')) {
    body = await c.req.text().catch(() => undefined)
  }
} catch {
  // Ignore parsing errors, body remains undefined
}

const setMiddlewareExtension = <E extends Env = Env>(
  middleware: MiddlewareHandler<E>,
  options: XMiddlewareOptions,
): XMiddlewareHandler<E> => {
  const { functionName, type, name, description } = options;

  // Store metadata in global map for later collection
  if (description) {
    extensionValueMetadata.set(`${type}:${functionName}`, { name, description });
  }
  // Object.assign creates intersection type that TypeScript understands
  const extended = Object.assign(middleware, {
    __extensionType: type,
    __description: description,
  });
  // name requires Object.defineProperty since function.name is read-only in JS
  Object.defineProperty(extended, 'name', { value: functionName, writable: false });
  return extended;
};

