      .from(attachmentsTable)
      .leftJoin(productCountersTable, eq(productCountersTable.entityId, attachmentsTable.id))
      .leftJoin(createdByUser, eq(createdByUser.id, attachmentsTable.createdBy))
      .leftJoin(updatedByUser, eq(updatedByUser.id, attachmentsTable.updatedBy))
      .where(whereClause)
      .orderBy(orderColumn)
      .limit(limit)
      .offset(offset),
    db.select({ total: count() }).from(attachmentsTable).where(whereClause),
  ]);

  return { rawItems, total };
});

const getEntityCounts = async ({ var: { db } }: DbContext, entityType: ContextEntityType, entityId: string) => {
  const { countsSelect } = getEntityCountsSelect(entityType);

  const [counts] = await db
    .select(countsSelect)
    .from(contextCountersTable)
    .where(eq(contextCountersTable.contextKey, entityId));

  // If no row exists yet, return zeroed counts
  if (!counts) {
    const zeroMembership = Object.fromEntries([...roles.all.map((r) => [r, 0]), ['pending', 0], ['total', 0]]);
    const zeroEntities = Object.fromEntries(hierarchy.getOrderedDescendants(entityType).map((e) => [e, 0]));
    return {
      membership: zeroMembership as z.infer<typeof membershipCountSchema>,
      entities: zeroEntities as Record<string, number>,
    };
  }

  return counts;
};

